const body = $input.item.json.body || {};
const id = String(body.auction_id || '').trim();
const handle = String(body.handle || body.email || body.name || '').trim().slice(0, 120);
let maxCents = body.max_cents != null ? parseInt(body.max_cents, 10) : null;
const pi = String(body.payment_intent_id || '').trim();
if (!id) return { json: { ok: false, status: 400, error: 'auction_id required' } };
if (!handle) return { json: { ok: false, status: 400, error: 'name or email required' } };
if (maxCents == null || isNaN(maxCents) || maxCents <= 0) return { json: { ok: false, status: 400, error: 'max_cents required' } };
if (!pi) return { json: { ok: false, status: 400, error: 'payment_intent_id required' } };
return { json: { auction_id: id, handle: handle, max_cents: maxCents, payment_intent_id: pi } };

const s = $input.item.json || {};
const x = $('Extract').item.json;
if (s.error) return { json: { ok: false, status: 502, error: 'Stripe: ' + (s.error.message || 'lookup failed') } };
if (!s.id) return { json: { ok: false, status: 400, error: 'Payment authorization not found' } };
if (s.status !== 'requires_capture') return { json: { ok: false, status: 402, error: 'Card was not authorized (status: ' + s.status + ')' } };
const meta = s.metadata || {};
if (String(meta.auction_id || '') !== x.auction_id) return { json: { ok: false, status: 400, error: 'Authorization does not match this auction' } };
if (parseInt(s.amount, 10) !== x.max_cents) return { json: { ok: false, status: 400, error: 'Authorized amount does not match your max' } };
return { json: { ok: true, auction_id: x.auction_id, handle: x.handle, max_cents: x.max_cents, payment_intent_id: x.payment_intent_id } };

let r = $input.item.json; if (Array.isArray(r)) r = r[0] || {};
if (r == null || typeof r !== 'object') r = { ok: false, status: 500, error: 'Unexpected DB response' };
if (!r.ok) return { json: { ok: false, status: r.status || 500, error: r.error || 'Bid failed', has_old: false, old_pi: null } };
const res = r.resolution || {};
return { json: {
  ok: true, status: 200,
  max_display: '$' + ((r.max_cents || 0) / 100).toFixed(2),
  leading: !!res.auto_bid,
  new_high_display: res.amount_cents != null ? ('$' + (res.amount_cents / 100).toFixed(2)) : null,
  has_old: !!r.cancel_payment_intent,
  old_pi: r.cancel_payment_intent || null
} };
